import{_ as r,o as t,c as n,j as e,a as s,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"蛇形刁手","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/6.技艺及称号/武技类/肉搏类/蛇形刁手.md","filePath":"4.资源分区/6.技艺及称号/武技类/肉搏类/蛇形刁手.md"}'),d={name:"4.资源分区/6.技艺及称号/武技类/肉搏类/蛇形刁手.md"};function l(_,a,i,p,c,h){return t(),n("div",null,[...a[0]||(a[0]=[e("h1",{id:"蛇形刁手",tabindex:"-1"},[s("蛇形刁手 "),e("a",{class:"header-anchor",href:"#蛇形刁手","aria-label":'Permalink to "蛇形刁手"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：汹涌疾风023")])])],-1),o('<h1 id="蛇形刁手-1" tabindex="-1">蛇形刁手 <a class="header-anchor" href="#蛇形刁手-1" aria-label="Permalink to &quot;蛇形刁手&quot;">​</a></h1><p>蛇形刁手<br> D+500<br> 购买该技艺时会得到一条滑稽的绿色蛇形长筒袜，只有戴上这条蛇袜才能发挥蛇形刁手的完全力量。<br> 本质是戴上蛇袜进行自我暗示和催眠，使自己认为蛇形刁手已经成为了一条有自己思想，攻击性极强并带有致命毒液的眼镜蛇。<br> 在施展蛇形刁手时，你需要以一个迅捷动作为右手戴上蛇袜并以一连串的动作拉动右臂进行自我催眠，之后以一个标准动作使用蛇形刁手进行一次肉搏攻击。这是一次针对头部的特殊部位攻击，本次攻击获得2点武器伤害，并且减少3点特殊部位减值，获得3DP的技艺加值，并且受到伤害的目标需要进行一个DC=伤害数的反射豁免，失败则被立即击倒。<br> 理所当然的，当你免疫催眠，暗示等效果时，自我暗示会失效，攻击变为一次普通的针对头部的特殊部位攻击。<br> 同理，因为你的自我催眠，你的右臂会认为自己是一条真正的蛇，会被任何针对蛇的效果影响，包括但不限于蛇癖，印度耍蛇人的笛子……此时你无法解除自我暗示，直到攻击结束。</p><hr><p>Copyright ? 2024 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',4)])])}const m=r(d,[["render",l]]);export{f as __pageData,m as default};
